import React from 'react';
import { useLocation, Link } from 'react-router-dom';
import { BreadCrumb } from 'primereact/breadcrumb';

export const AppBreadcrumb = () => {
    const location = useLocation();

    // 1. Split the path, remove empty strings, and generate the model
    const pathnames = location.pathname.split('/').filter((x) => x);

    const model = pathnames.map((value, index) => {
        // Create the cumulative path for the link (e.g. /operations/jobs)
        const to = `/${pathnames.slice(0, index + 1).join('/')}`;

        return {
            // Capitalize first letter for better UI, or remove this to keep raw URL text
            label: value.charAt(0).toUpperCase() + value.slice(1),
            url: to,
            template: (item: any, options: any) => (
                <Link
                    to={item.url}
                    className={options.className}
                    onClick={options.onClick}
                >
                    <span className={options.labelClassName}>{item.label}</span>
                </Link>
            )
        };
    });

    const home = {
        icon: 'pi pi-home',
        url: '/',
        template: (item: any, options: any) => (
            <Link to="/" className={options.className} onClick={options.onClick}>
                <span className={`pi pi-home ${options.iconClassName}`}></span>
            </Link>
        )
    };

    return (
        <BreadCrumb style={{backgroundColor:'inherit'}} model={model} home={home} />
    );
};

export default AppBreadcrumb;
